   131	  bool startOfLine = false;
   132	  bool leadingSpace = false;
   133	
   134	  // Check if token is at start of line (but not EOF)
   135	  // A token is at start of line if it's the first non-whitespace token on that line
   136	  if (token->getType() != antlr4::Token::EOF) {
   137	    auto tokenIndex = token->getTokenIndex();
   138	    if (tokenIndex > 0) {
   139	      auto prevToken = tokens.getTokens()[tokenIndex - 1];
   140	      // Check if previous token is on a different line
   141	      if (prevToken->getLine() != line) {
   142	        startOfLine = true;
   143	      }
   144	    } else {
   145	      // First token in the file
   146	      startOfLine = true;
   147	    }
   148	    
   149	    // Check if token has leading space using hidden tokens
   150	    if (tokenIndex > 0) {
   151	      auto hiddenTokensToLeft = tokens.getHiddenTokensToLeft(tokenIndex);
   152	      if (!hiddenTokensToLeft.empty()) {
   153	        auto lastHidden = hiddenTokensToLeft.back();
   154	        // Check if the last hidden token is whitespace (not newline)
   155	        if (lastHidden->getChannel() == antlr4::Token::HIDDEN_CHANNEL) {
   156	          auto hiddenText = lastHidden->getText();
   157	          // Check if it contains whitespace (not just newlines)
   158	          if (hiddenText.find(' ') != std::string::npos || 
   159	              hiddenText.find('\t') != std::string::npos) {
   160	            leadingSpace = true;
   161	          }
   162	        }
   163	      }
   164	    }
   165	  }
   166	
   167	  if (token->getText() != "<EOF>")
   168	    outFile << tokenTypeName << " '" << token->getText() << "'";
   169	  else
   170	    outFile << tokenTypeName << " '"
   171	            << "'";
   172	  if (startOfLine)
   173	    outFile << "\t [StartOfLine]";
   174	  if (leadingSpace)
   175	    outFile << " [LeadingSpace]";
